// // This full adder computes the sum and carry-out using XOR for sum and AND/OR for carry-out
module full_adder_1bit (
    input wire A,
    input wire B,
    input wire Cin,
    output wire S,
    output wire Cout
    );

assign S = A ^ B ^ Cin;
assign Cout = (A & B) | (Cin & (A ^ B));

endmodule
